// Generates `src/registry.generated.ts` by scanning `src/capabilities/*`. Each
// folder with a `capability.ts` is a capability; each file in its `operations/`
// folder is an operation. This runs before every dev, build, typecheck, and
// publish (see package.json), so:
//   - adding a capability = adding one folder (with capability.ts)
//   - adding an operation  = adding one file under <cap>/operations/
// Either way you touch only your own new file, so PRs never conflict. The
// generated file is git-ignored on purpose.
import { readdirSync, writeFileSync, existsSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const here = dirname(fileURLToPath(import.meta.url));
const capsDir = join(here, "..", "src", "capabilities");
const outFile = join(here, "..", "src", "registry.generated.ts");

const caps = existsSync(capsDir)
  ? readdirSync(capsDir, { withFileTypes: true })
      .filter((d) => d.isDirectory() && existsSync(join(capsDir, d.name, "capability.ts")))
      .map((d) => d.name)
      .sort()
  : [];

const imports = ["import { assemble } from './assemble';"];
const entries = [];
let opCount = 0;

caps.forEach((cap, i) => {
  imports.push(`import { meta as m${i} } from "./capabilities/${cap}/capability";`);
  const opsDir = join(capsDir, cap, "operations");
  const ops = existsSync(opsDir)
    ? readdirSync(opsDir)
        .filter((f) => f.endsWith(".ts"))
        .map((f) => f.replace(/\.ts$/, ""))
        .sort()
    : [];
  const aliases = ops.map((op, j) => {
    const alias = `o${i}_${j}`;
    imports.push(`import { operation as ${alias} } from "./capabilities/${cap}/operations/${op}";`);
    return alias;
  });
  opCount += ops.length;
  entries.push(`  assemble(m${i}, [${aliases.join(", ")}]),`);
});

const body = `// AUTO-GENERATED by scripts/gen-registry.mjs — do not edit.
// Regenerated from src/capabilities/* before every dev, build, typecheck, and publish.
import type { CapabilityModule } from "./types";
${imports.join("\n")}

export const capabilities: CapabilityModule[] = [
${entries.join("\n")}
];
`;

writeFileSync(outFile, body);
console.log(`registry: ${caps.length} capabilities, ${opCount} operations (${caps.join(", ")})`);
